practice_tasks.solution:
class Discount:
  def apply(self, order_total):
    raise NotImplementedError

class PercentDiscount(Discount):
  def __init__(self, amount):
    self.amount = amount
  def apply(self, order_total):
    return order_total - (order_total * self.amount / 100)

class FixedDiscount(Discount):
  def __init__(self, amount):
    self.amount = amount
  def apply(self, order_total):
    return order_total - self.amount

class DiscountCalculator:
  def calculate(self, order_total, discount: Discount):
    return discount.apply(order_total)

calc = DiscountCalculator()
print(calc.calculate(100, PercentDiscount(10)))

