class Formatter:
  def format(self, text):
    return text

class UpperFormatter(Formatter):
  def format(self, text):
    return text.upper()

def print_message(text, formatter=Formatter()):
  print(formatter.format(text))

print_message('hello', UpperFormatter())

challenge.solution:
class Notifier:
  def send(self, message):
    raise NotImplementedError

class EmailNotifier(Notifier):
  def send(self, message):
    print(f'Emailing: {message}')

class SMSNotifier(Notifier):
  def send(self, message):
    print(f'SMSing: {message}')

class SystemAlert:
  def __init__(self, notifiers):
    self.notifiers = notifiers
  def alert(self, message):
    for n in self.notifiers:
      n.send(message)

alert = SystemAlert([EmailNotifier(), SMSNotifier()])
alert.alert('Server down!')

